    private void filterLinkableFields(LinkedList<CellInfo> linkableFields, HashSet<Integer> usedIdSet, NUIForm linkForm, NUIForm currentForm, int subKeyDomainId) {
        List<CellInfo> addFieldList = linkForm.getAllFields(true);
        for (CellInfo info : addFieldList) {
            int _id = info.getDomainId();
            boolean validSubtableField=subKeyDomainId == linkForm.getTableHeaderDomain(_id);
            boolean validSingleField=linkForm.getLevel(_id)==Const.SINGLE;

            if (currentForm.hasDomainId(_id) || usedIdSet.contains(_id) || !currentForm.getFieldsByAttribute("vd",""+_id).isEmpty() ||
                    info.getAttribute("interm") != null || (!validSingleField && !validSubtableField)) continue;
//            String interm = String.valueOf(linkForm.getRootDomainId());
//            int subtableParentAlias = linkForm.getSubtableParentAlias(subKeyDomainId);

            CellInfo setInfo = info.copy();
            if (validSingleField) {
//                setInfo.setAttribute("interm", (subtableParentAlias == Const.NODOMAIN ? interm : "" + subtableParentAlias));
//                setInfo.setAttribute("ro", "true");
                CellInfo linkedField=currentForm.getFieldByAttribute("mvp",linkForm.getPath()+"|"+linkForm.getFormName()); //[issue:13780]
                if(linkedField==null || currentForm.getLevel(linkedField.getDomainId())!=Const.SINGLE) linkedField=currentForm.getFieldByAttribute("s",""+linkForm.getRootDomainId());
                if(linkedField==null || currentForm.getLevel(linkedField.getDomainId())!=Const.SINGLE) linkedField=currentForm.getField(linkForm.getRootDomainId());
                if(linkedField!=null && currentForm.getLevel(linkedField.getDomainId())==Const.SINGLE){
                    setInfo.setAttribute("l", ""+linkedField.getDomainId());
                    setInfo.setAttribute("vd", ""+info.getDomainId());
                    setInfo.setAttribute("ro", "1");
                    setInfo.setAttribute("lnlsselect", "1");
                    //[BugId:13845]
                    if (setInfo.getAttribute("mvp") != null && setInfo.getAttribute("s") == null) {
                        setInfo.setAttribute("s", ""+info.getDomainId());
                    }
                    HashMap<String, String> attrs = (HashMap<String, String>) setInfo.getAttributes();
                    setInfo.setAttributeString(setInfo.recreateAttributeString(attrs));
                    linkableFields.add(setInfo);
                    usedIdSet.add(_id);
                }
            } else if (validSubtableField) {
                if (setInfo.getAttribute("ag") != null) {
                    setInfo.setAttribute("ag", setInfo.getAttribute("ag").replace("{SUBTABLE_RAGIC_ID}", "{RAGIC_ID}"));
                }
                linkableFields.addFirst(setInfo);
                usedIdSet.add(_id);
            }
        }
    }

